// NODE 2 — Validar entrada (V24B — idéntico a R5)
const body = $input.first().json?.body ?? $input.first().json;
const rawId = body?.entregable_version_id;
const modo  = String(body?.modo ?? 'EXPORT').toUpperCase();
if (rawId === undefined || rawId === null || rawId === '') {
  return [{ json: { valid: false, validation_error: 'entregable_version_id_requerido', mensaje: 'Debe enviar entregable_version_id.', entregable_version_id: -1, raw_entregable_version_id: rawId, modo } }];
}
const id = Number(rawId);
if (!Number.isInteger(id) || id <= 0) {
  return [{ json: { valid: false, validation_error: 'entregable_version_id_invalido', mensaje: 'entregable_version_id debe ser un entero positivo.', entregable_version_id: -1, raw_entregable_version_id: rawId, modo } }];
}
return [{ json: { valid: true, validation_error: '', mensaje: '', entregable_version_id: id, raw_entregable_version_id: rawId, modo } }];

// NODE 5 — V24B: HTML Auditado con scoring determinístico
const EXPORTADOR_VERSION = 'V24B_HTML_DOCUMENTAL_AUDITADO';
const mainRows = $('PG_LeerEntregableVersion').all().map(i => i.json);
const pyrRowsRaw = $('PG_LeerRespuestasEntrevista').all().map(i => i.json);
const pyrRows = pyrRowsRaw.filter(p => p && (p.pyr_found === true || p.pyr_found === 't' || p.pyr_found === 1 || p.pyr_found === 'true') && (p.id_pregunta || p.pregunta_texto_snapshot));
const ctx = $('Code_ValidarEntrada').first().json;

if (ctx.validation_error) {
  return [{ json: { ok: false, error: ctx.validation_error, entregable_version_id: ctx.raw_entregable_version_id ?? null, exportador_version: EXPORTADOR_VERSION, mensaje: ctx.mensaje || 'Error de validación de entrada.' } }];
}

const main = mainRows[0] || {};
const notFound = !mainRows.length || main.found === false || main.found === 'f' || main.found === 0 || main.found === '0';
if (notFound) {
  return [{ json: { ok: false, error: 'entregable_no_encontrado', entregable_version_id: ctx.entregable_version_id, exportador_version: EXPORTADOR_VERSION, mensaje: 'No existe una versión de entregable con el ID solicitado.' } }];
}

const r = main;

// ── helpers ──
const esc = s => String(s ?? '').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;').replace(/'/g,'&#39;');
const hasVal = v => !(v === null || v === undefined || v === '' || (Array.isArray(v) && !v.length));
const hasArr = v => Array.isArray(v) && v.length > 0;
const first = (...vals) => { for (const v of vals) if (hasVal(v)) return String(v).trim(); return 'N/D'; };
const bool = v => v === true || v === 't' || v === 'true' || v === 1 || v === '1';
const fmt = s => { if (!s) return 'N/D'; try { return new Date(s).toLocaleString('es-CR',{timeZone:'America/Costa_Rica',dateStyle:'long',timeStyle:'short'}); } catch(e) { return String(s); } };
const fmtDate = s => { if (!s) return 'N/D'; try { return new Date(s).toLocaleDateString('es-CR',{timeZone:'America/Costa_Rica',year:'numeric',month:'long',day:'numeric'}); } catch(e) { return String(s); } };

// ── parse JSON columns ──
let parseErrors = [];
function parseMJ(value, fallback, label) {
  if (value === null || value === undefined || value === '') return fallback;
  if (typeof value === 'object') return value;
  try { return JSON.parse(value); } catch(e) { parseErrors.push(label + ': ' + e.message); return fallback; }
}
const objeto = parseMJ(r.objeto_estandar_json, {}, 'objeto_estandar_json');
const ficha  = parseMJ(r.ficha_analitica_json, {}, 'ficha_analitica_json');
const qa     = parseMJ(r.revision_qa_json, {}, 'revision_qa_json');
const peRaw  = parseMJ(r.parse_errors, [], 'parse_errors');
if (Array.isArray(peRaw)) parseErrors = parseErrors.concat(peRaw);

// ── resolved fields ──
const codigoExpediente  = first(r.codigo_expediente);
const nombreColaborador = first(r.nombre_completo, r.nombre_colaborador_legacy);
const idColaborador     = first(r.identificador_colaborador, r.cedula_legacy);
const nombreCargo       = first(r.nombre_cargo_normalizado, r.cargo_actual_legacy);
const areaCargo         = first(r.area_legacy);
const version           = first(r.version);
const versionGenerador  = first(r.version_generador);
const estadoQA          = first(r.estado_qa_resumido);
const aptoEntrega       = bool(r.apto_para_entrega);
const requiereRH        = bool(r.requiere_revision_humana);
const filename          = 'entregable_' + r.entregable_version_id + '_' + codigoExpediente + '_auditado.html';

// ── sub-objects ──
const perfil  = objeto.perfil_requerido || ficha.perfil_requerido || {};
const difMej  = objeto.dificultades_mejoras || ficha.dificultades_mejoras || {};
const relacs  = objeto.relaciones || ficha.relaciones || {};
const tiempos = objeto.tiempos_carga_laboral || ficha.tiempos_carga_laboral || {};

// ── SCORING ALGORITHM ──
const CRITERIOS = [
  { id:'proposito',            label:'Propósito del cargo',                peso:2, value: objeto.proposito || ficha.proposito },
  { id:'funciones_clave',      label:'Funciones clave',                     peso:2, value: objeto.funciones_clave || ficha.funciones_clave },
  { id:'responsabilidades',    label:'Responsabilidades',                   peso:2, value: objeto.responsabilidades || ficha.responsabilidades },
  { id:'perfil_estudios',      label:'Perfil: estudios / formación',        peso:1, value: perfil.estudios || perfil.formacion },
  { id:'perfil_experiencia',   label:'Perfil: experiencia',                 peso:1, value: perfil.experiencia },
  { id:'perfil_competencias',  label:'Perfil: competencias',                peso:1, value: perfil.competencias },
  { id:'perfil_herramientas',  label:'Perfil: herramientas / sistemas',     peso:1, value: perfil.herramientas || perfil.sistemas },
  { id:'perfil_conocimientos', label:'Perfil: conocimientos técnicos',      peso:1, value: perfil.conocimientos },
  { id:'indicadores',          label:'Indicadores sugeridos (KPIs)',        peso:2, value: objeto.indicadores_sugeridos || ficha.indicadores_sugeridos },
  { id:'mejoras',              label:'Mejoras identificadas',               peso:1, value: difMej.mejoras },
  { id:'reprocesos',           label:'Reprocesos identificados',            peso:1, value: difMej.reprocesos },
  { id:'dificultades',         label:'Dificultades específicas',            peso:1, value: difMej.dificultades },
  { id:'relaciones_internas',  label:'Relaciones internas del cargo',       peso:1, value: relacs.internas },
  { id:'tiempos_frecuencias',  label:'Tiempos: frecuencias de actividades', peso:1, value: tiempos.frecuencias },
  { id:'tiempos_actividades',  label:'Tiempos: actividades de mayor carga', peso:1, value: tiempos.actividades_mayor_tiempo },
  { id:'alertas_vacios',       label:'Alertas y vacíos documentados',       peso:1, value: objeto.alertas_vacios },
  { id:'pyr',                  label:'Preguntas y Respuestas de entrevista',peso:2, value: pyrRows.length > 0 ? pyrRows : null },
];

CRITERIOS.forEach(c => {
  c.presente = hasVal(c.value) && (Array.isArray(c.value) ? c.value.length > 0 : String(c.value).trim().length > 2);
});

const totalPeso   = CRITERIOS.reduce((s,c) => s + c.peso, 0);
const pesoPresente = CRITERIOS.reduce((s,c) => c.presente ? s + c.peso : s, 0);
const scoreCompletitud = Math.round((pesoPresente / totalPeso) * 100);

const tieneBase   = CRITERIOS.find(c=>c.id==='proposito')?.presente && CRITERIOS.find(c=>c.id==='funciones_clave')?.presente;
const tieneResp   = CRITERIOS.find(c=>c.id==='responsabilidades')?.presente;
const tienePerfilAlguno = ['perfil_estudios','perfil_experiencia','perfil_competencias'].some(id => CRITERIOS.find(c=>c.id===id)?.presente);
const tieneIndicadores  = CRITERIOS.find(c=>c.id==='indicadores')?.presente;
const faltanCriticos    = !tieneIndicadores || !tienePerfilAlguno;

let estadoDocumental;
if (aptoEntrega && !requiereRH)                                      estadoDocumental = 'APTO_ENTREGA';
else if (tieneBase && tieneResp && (tienePerfilAlguno || tieneIndicadores)) estadoDocumental = faltanCriticos ? 'REQUIERE_REVISION' : 'APTO_REVISION';
else if (tieneBase)                                                   estadoDocumental = 'REQUIERE_REVISION';
else                                                                  estadoDocumental = 'BORRADOR_QA';

const brechas = CRITERIOS.filter(c => !c.presente).map(c => ({ campo: c.id, label: c.label, peso: c.peso, critico: c.peso >= 2 }));

// ── HTML helpers ──
const fieldRow = (label, value) => '<tr><th>' + esc(label) + '</th><td>' + esc(first(value)) + '</td></tr>';
const tbl = rows => '<table>' + rows + '</table>';
const sec = (id, title, content) => '<section id=\'' + id + '\'><h2>' + esc(title) + '</h2>' + content + '</section>';

function valToTxt(v) {
  if (v === null || v === undefined || v === '') return 'N/D';
  if (Array.isArray(v)) return v.length ? v.map(x => typeof x === 'object' ? JSON.stringify(x) : String(x)).join('; ') : 'N/D';
  if (typeof v === 'object') return JSON.stringify(v);
  return String(v);
}
function objRows(obj, prefix) {
  prefix = prefix || '';
  if (!obj || typeof obj !== 'object') return fieldRow(prefix || 'Valor', valToTxt(obj));
  return Object.entries(obj).map(function(entry) {
    const k = entry[0], v = entry[1];
    const label = prefix ? prefix + ' › ' + k : k;
    if (v && typeof v === 'object' && !Array.isArray(v)) return objRows(v, label);
    return '<tr><th>' + esc(label) + '</th><td>' + esc(valToTxt(v)) + '</td></tr>';
  }).join('');
}
function buildList(value) {
  if (!hasVal(value)) return '<p class=\'pendiente\'><em>Pendiente de validación / no disponible en la versión actual.</em></p>';
  if (Array.isArray(value)) {
    if (!value.length) return '<p class=\'pendiente\'><em>Pendiente de validación / no disponible en la versión actual.</em></p>';
    return '<ul>' + value.map(function(item) { return '<li>' + esc(typeof item === 'object' ? JSON.stringify(item) : String(item)) + '</li>'; }).join('') + '</ul>';
  }
  return '<p>' + esc(String(value)) + '</p>';
}

// ── Semáforo ──
const semColors = { APTO_ENTREGA:'#2e7d32', APTO_REVISION:'#0288d1', REQUIERE_REVISION:'#ed6c02', BORRADOR_QA:'#d32f2f' };
const semLabels = { APTO_ENTREGA:'✓ Apto para entrega', APTO_REVISION:'◑ Apto para revisión', REQUIERE_REVISION:'⚠ Requiere revisión', BORRADOR_QA:'✗ Borrador QA' };
const semColor  = semColors[estadoDocumental] || '#666';
const semLabel  = semLabels[estadoDocumental] || estadoDocumental;

const aptoColor = aptoEntrega ? '#2e7d32' : '#d32f2f';
const aptoTxt   = aptoEntrega ? 'Sí' : 'No';
const revColor  = requiereRH ? '#ed6c02' : '#2e7d32';
const revTxt    = requiereRH ? 'Sí' : 'No';

function scoreBar(score) {
  const color = score >= 80 ? '#2e7d32' : score >= 55 ? '#ed6c02' : '#d32f2f';
  return '<div style=\'background:#eee;border-radius:4px;height:18px;width:100%;margin:8px 0\'><div style=\'background:' + color + ';width:' + score + '%;height:100%;border-radius:4px\'></div></div>' +
         '<div style=\'font-size:12px;color:' + color + ';font-weight:700\'>' + score + '% completitud</div>';
}

// sec0 — Semáforo + score
const sec0 = '<section id=\'s0\'>' +
  '<h2>Estado Documental y Completitud</h2>' +
  '<div style=\'display:flex;gap:28px;flex-wrap:wrap;align-items:flex-start;margin-bottom:16px\'>' +
    '<div style=\'min-width:150px;padding:14px 18px;border-radius:8px;background:' + semColor + ';color:#fff;text-align:center\'>' +
      '<div style=\'font-size:18px;font-weight:900\'>' + esc(semLabel) + '</div>' +
      '<div style=\'font-size:10px;margin-top:4px;opacity:.85\'>' + esc(estadoDocumental) + '</div>' +
    '</div>' +
    '<div style=\'flex:1;min-width:200px\'>' +
      scoreBar(scoreCompletitud) +
      '<table style=\'margin-top:8px;width:auto;font-size:12px\'>' +
        '<tr><th>Apto para entrega</th><td style=\'color:' + aptoColor + ';font-weight:700\'>' + aptoTxt + '</td></tr>' +
        '<tr><th>Requiere revisión humana</th><td style=\'color:' + revColor + ';font-weight:700\'>' + revTxt + '</td></tr>' +
        '<tr><th>Estado QA</th><td>' + esc(estadoQA) + '</td></tr>' +
        '<tr><th>Calidad general</th><td>' + esc(first(r.calidad_general)) + '</td></tr>' +
        '<tr><th>Brechas</th><td>' + brechas.length + ' (' + brechas.filter(function(b){return b.critico;}).length + ' críticas)</td></tr>' +
      '</table>' +
    '</div>' +
  '</div>' +
'</section>';

// sec_brecha — Matriz de brechas
function buildBrechas() {
  if (!brechas.length) return '<p style=\'color:#2e7d32;font-weight:700\'>Sin brechas detectadas. Documento completo.</p>';
  const criticas = brechas.filter(function(b){return b.critico;});
  const normales = brechas.filter(function(b){return !b.critico;});
  let html = '';
  if (criticas.length) {
    html += '<h3 style=\'color:#d32f2f\'>Brechas críticas (' + criticas.length + ')</h3><ul>';
    criticas.forEach(function(b) { html += '<li><strong>' + esc(b.label) + '</strong> — pendiente de validación / no disponible en la versión actual.</li>'; });
    html += '</ul>';
  }
  if (normales.length) {
    html += '<h3 style=\'color:#ed6c02\'>Brechas complementarias (' + normales.length + ')</h3><ul>';
    normales.forEach(function(b) { html += '<li>' + esc(b.label) + ' — pendiente de validación / no disponible en la versión actual.</li>'; });
    html += '</ul>';
  }
  return html;
}
const secBrecha = sec('s_brecha', 'Matriz de Brechas Documentales', buildBrechas());

// sec_completitud — Matriz de completitud
function buildMatriz() {
  const rows = CRITERIOS.map(function(c) {
    const ico = c.presente ? '✓' : '✗';
    const clr = c.presente ? '#2e7d32' : '#d32f2f';
    const crit = c.peso >= 2 ? '<span style=\'color:#b45309;font-size:11px\'> ★</span>' : '';
    return '<tr>' +
      '<td style=\'color:' + clr + ';font-weight:700;text-align:center\'>' + ico + '</td>' +
      '<td>' + esc(c.label) + crit + '</td>' +
      '<td style=\'text-align:center\'>' + c.peso + '</td>' +
      '<td style=\'color:' + clr + '\'>' + (c.presente ? 'Disponible' : 'Pendiente') + '</td>' +
    '</tr>';
  }).join('');
  return '<table>' +
    '<thead><tr><th style=\'width:30px\'>✓/✗</th><th>Campo</th><th style=\'width:44px\'>Peso</th><th>Estado</th></tr></thead>' +
    '<tbody>' + rows + '</tbody></table>' +
    '<p style=\'font-size:11px;color:#666;margin-top:4px\'>★ = campo crítico (peso ≥ 2)</p>';
}
const secCompletitud = sec('s_completitud', 'Matriz de Completitud por Sección', buildMatriz());

// sec_rec — Recomendaciones de revisión humana
function buildRecomendaciones() {
  const items = [];
  if (!tieneIndicadores) items.push('Completar indicadores sugeridos (KPIs) con el colaborador o supervisor directo.');
  if (!tienePerfilAlguno) items.push('Levantar perfil requerido: estudios, experiencia y competencias clave.');
  if (!CRITERIOS.find(function(c){return c.id==='mejoras';})?.presente) items.push('Documentar mejoras y reprocesos identificados en el puesto.');
  if (!CRITERIOS.find(function(c){return c.id==='relaciones_internas';})?.presente) items.push('Mapear relaciones internas y externas del cargo.');
  if (requiereRH) items.push('Nivel de revisión humana requerida: ' + first(r.nivel_revision_humana) + '.');
  if (!aptoEntrega) items.push('El entregable no está aprobado para entrega formal. Validar con el equipo RRHH antes de distribuir.');
  if (!items.length) return '<p style=\'color:#2e7d32\'>No hay recomendaciones de revisión pendientes.</p>';
  return '<ol>' + items.map(function(i){ return '<li>' + esc(i) + '</li>'; }).join('') + '</ol>';
}
const secRec = sec('s_rec', 'Recomendaciones de Revisión Humana', buildRecomendaciones());

// sec1 — Identificación
const sec1 = sec('s1', '1. Identificación del Documento',
  tbl(
    fieldRow('Código Expediente', codigoExpediente) +
    fieldRow('Entregable Version ID', r.entregable_version_id) +
    fieldRow('Entregable ID', r.entregable_id) +
    fieldRow('Versión', version) +
    fieldRow('Generador (agente)', versionGenerador) +
    fieldRow('Exportador', EXPORTADOR_VERSION) +
    fieldRow('Score completitud', scoreCompletitud + '%') +
    fieldRow('Estado documental', estadoDocumental) +
    fieldRow('Archivo sugerido', filename) +
    fieldRow('Fecha generación export', fmt(new Date().toISOString()))
  )
);

// sec2 — Expediente
const sec2 = sec('s2', '2. Datos del Expediente',
  tbl(
    fieldRow('Estado Expediente', r.estado_expediente) +
    fieldRow('Estado Generación', r.estado_generacion) +
    fieldRow('Modo', r.modo) +
    fieldRow('Progreso (%)', r.progreso_pct) +
    fieldRow('Fecha Inicio', fmtDate(r.fecha_inicio)) +
    fieldRow('Fecha Cierre', fmtDate(r.fecha_cierre)) +
    fieldRow('Última Generación', fmt(r.fecha_ultima_generacion)) +
    fieldRow('Total Preguntas Canónicas', r.total_preguntas_canonicas) +
    fieldRow('Total Respuestas Históricas', r.total_respuestas_historicas)
  )
);

// sec3 — Colaborador
const sec3 = sec('s3', '3. Datos del Colaborador',
  tbl(fieldRow('Nombre Completo', nombreColaborador) + fieldRow('Identificador', idColaborador))
);

// sec4 — Cargo
const sec4 = sec('s4', '4. Cargo Levantado',
  tbl(fieldRow('Nombre del Cargo', nombreCargo) + fieldRow('Área', areaCargo))
);

// sec5 — QA
const sec5 = sec('s5', '5. Revisión QA y Control de Calidad',
  tbl(
    fieldRow('Estado QA Resumido', estadoQA) +
    fieldRow('Calidad General', r.calidad_general) +
    fieldRow('Apto para Entrega', aptoTxt) +
    fieldRow('Requiere Revisión Humana', revTxt) +
    fieldRow('Nivel Revisión Humana', r.nivel_revision_humana)
  ) + (Object.keys(qa).length ? '<h3>Detalle revisión QA</h3>' + tbl(objRows(qa)) : '<p class=\'empty\'>Sin detalle JSON de revisión QA.</p>')
);

// sec6 — Propósito y funciones
const proposito = objeto.proposito || ficha.proposito;
const funciones = objeto.funciones_clave || ficha.funciones_clave;
const responsabilidades = objeto.responsabilidades || ficha.responsabilidades;
const indicadores = objeto.indicadores_sugeridos || ficha.indicadores_sugeridos;
const alertasVacios = objeto.alertas_vacios;
const observacionesQA = objeto.observaciones_qa;

const sec6 = sec('s6', '6. Objeto Estándar — Descripción de Puesto',
  '<h3>Propósito del cargo</h3>' + buildList(proposito) +
  '<h3>Funciones clave</h3>' + buildList(funciones) +
  '<h3>Responsabilidades</h3>' + buildList(responsabilidades) +
  '<h3>Indicadores sugeridos (KPIs)</h3>' + buildList(indicadores) +
  '<h3>Alertas y vacíos</h3>' + buildList(alertasVacios) +
  (hasVal(observacionesQA) ? '<h3>Observaciones QA</h3><p>' + esc(observacionesQA) + '</p>' : '')
);

// sec7 — Perfil requerido
const sec7 = sec('s7', '7. Perfil Requerido del Cargo',
  Object.keys(perfil).length
    ? tbl(objRows(perfil))
    : '<p class=\'pendiente\'><em>Pendiente de validación / no disponible en la versión actual.</em></p>'
);

// sec8 — Dificultades, mejoras, reprocesos
const sec8 = sec('s8', '8. Dificultades, Mejoras y Reprocesos',
  Object.keys(difMej).length
    ? '<h3>Mejoras</h3>' + buildList(difMej.mejoras) +
      '<h3>Reprocesos</h3>' + buildList(difMej.reprocesos) +
      '<h3>Dificultades</h3>' + buildList(difMej.dificultades)
    : '<p class=\'pendiente\'><em>Pendiente de validación / no disponible en la versión actual.</em></p>'
);

// sec9 — Relaciones y tiempos
const sec9 = sec('s9', '9. Relaciones y Carga Laboral',
  (Object.keys(relacs).length ? '<h3>Relaciones</h3>' + tbl(objRows(relacs)) : '<p class=\'pendiente\'><em>Relaciones: pendiente de validación.</em></p>') +
  (Object.keys(tiempos).length ? '<h3>Tiempos y carga laboral</h3>' + tbl(objRows(tiempos)) : '<p class=\'pendiente\'><em>Tiempos: pendiente de validación.</em></p>')
);

// sec10 — Ficha analítica
const sec10 = sec('s10', '10. Ficha Analítica del Cargo',
  Object.keys(ficha).length
    ? tbl(objRows(ficha))
    : '<p class=\'empty\'>Sin datos en ficha_analitica_json.</p>'
);

// sec11 — P&R
let pyrContent = '';
if (pyrRows.length) {
  const grouped = {};
  pyrRows.forEach(function(p) {
    const fase = first(p.fase, 'General');
    if (!grouped[fase]) grouped[fase] = [];
    grouped[fase].push(p);
  });
  pyrContent = Object.entries(grouped).map(function(entry) {
    const fase = entry[0], items = entry[1];
    const rows = items.map(function(p) {
      const flags = [];
      if (p.requirio_repregunta === true || p.requirio_repregunta === 't') flags.push('repregunta');
      if (p.flag_calidad_baja   === true || p.flag_calidad_baja   === 't') flags.push('⚠ calidad baja');
      if (p.completa === false  || p.completa === 'f') flags.push('incompleta');
      const flagStr = flags.length ? ' <span class=\'flag\'>[' + esc(flags.join(', ')) + ']</span>' : '';
      return '<tr>' +
        '<td class=\'qid\'>' + esc(first(p.orden, p.id_pregunta)) + '</td>' +
        '<td class=\'qcode\'>' + esc(first(p.id_pregunta)) + '</td>' +
        '<td class=\'qtext\'>' + esc(first(p.pregunta_texto_snapshot)) + flagStr + '</td>' +
        '<td class=\'atext\'>' + esc(first(p.respuesta_final)) + '</td>' +
      '</tr>';
    }).join('');
    return '<h3>Fase: ' + esc(fase) + '</h3>' +
      '<table><thead><tr><th>#</th><th>ID</th><th>Pregunta</th><th>Respuesta</th></tr></thead><tbody>' + rows + '</tbody></table>';
  }).join('');
} else {
  pyrContent = '<p class=\'empty\'>No se encontraron respuestas de entrevista asociadas a este expediente.</p>';
}
